<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Err</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Sandboxed command failed: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> stderr</span><span style="color:#9399B2;">))</span></span>
